import React, {useState, useEffect} from "react";
import "./uploadposterCSS.css";
import Navbaremployee from "./upperlistemployee";
import Cookies from "universal-cookie";

export const UploadPoster = () => {
    const [search, setSearch] = useState('');
    const cookies=new Cookies();
    
    useEffect(() => {
        cookies.set('search',search,{path:'/'});
        console.log(cookies)
    },[search])

    const [image, setImage] = useState('');
    const [imageSrc, setImageSrc] = useState('');
    
    const updateImage = (e) => {
        e.preventDefault();
        setImage(e.target.value);
    };

    const handleSubmit = (e) => {
        e.preventDefault();
        displayImage();
    };

    const displayImage = async () => {
        try {
          // 使用fetch獲取img data
          const response = await fetch(image);

          if (!response.ok) {
            throw new Error('無法獲取圖片');
          }
    
          // 獲取圖片data的blob
          const blob = await response.blob();
          // 創建臨時URL
          const url = URL.createObjectURL(blob);
    
          // 设置图像 URL，以在页面上显示图像
          setImageSrc(url);
        } catch (err) {
          // 处理错误
          console.error(err);
          setImageSrc('');
        }
    };
    
    return(
        <>
            {/* <Navbaremployee setSearch={setSearch}/> */}
            {/* https://ottaster.com/js-upload-file/ */}
            <form onSubmit={(e) => handleSubmit(e)}>
                <label>
                    图像 URL:
                    <input
                        id="image"
                        type="text"
                        value={image}
                        onChange={updateImage}
                    />
                </label>
                <button type="submit">提交</button>
            </form>

            {imageSrc && (
                <div>
                    <h2>显示图像：</h2>
                    <img src={imageSrc} alt="用户输入的图像" style={{ maxWidth: '100%' }} />
                </div>
            )}
        </>
    );
};
export default UploadPoster;
